import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.5, "beta": 1.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0] if neighbors else None

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        if coords is not None:
            node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2 ) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        best_utility = -1.0
        best_target = neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0.0) if nc in node_dict else 0.0
            if u > best_utility:
                best_utility = u
                best_target = n
        return best_target

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2 ) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev or prev[goal] is None:
            return None
        curr = goal
        while prev.get(curr) is not None and prev.get(curr) != start:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.0)
    beta = model.get("beta", 1.0)
    best_score = -float('inf')
    best_target = None
    for tcoord in utilities:
        util = utilities[tcoord]
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.01:
            continue
        score = (util ** beta) / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_target = neighbors[0] if neighbors else None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_target = neigh_raw
        return best_target

    next_pos = find_next_on_path(current_pos, best_target)
    if next_pos is None or next_pos == current_pos:
        best_utility = -1.0
        best_target = neighbors[0] if neighbors else None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_target = neigh_raw
        return best_target

    # find matching neighbor or closest
    best_n = neighbors[0] if neighbors else None
    min_d = float('inf')
    for neigh in neighbors:
        nc = coord_to_tuple(neigh)
        if nc == next_pos:
            return neigh
        d = get_edge_distance(nc, next_pos)
        if d < min_d:
            min_d = d
            best_n = neigh
    return best_n

def run_evaluation(data_path, model):
    data_path = Path(data_path)
    eval_config_path = data_path / "eval_config.json"
    maps = []
    if eval_config_path.exists():
        try:
            with open(eval_config_path, "r") as f:
                config = json.load(f)
            print("Loaded eval_config.json")
            if isinstance(config, list):
                for item in config:
                    if isinstance(item, str):
                        maps.append(data_path / item)
                    elif isinstance(item, dict) and "map_path" in item:
                        maps.append(data_path / item["map_path"])
            elif isinstance(config, dict):
                if "maps" in config:
                    for m in config["maps"]:
                        maps.append(data_path / m)
                elif "map_paths" in config:
                    for m in config["map_paths"]:
                        maps.append(data_path / m)
        except Exception as e:
            print(f"Error loading config: {e}")
    if not maps:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        map_types = ["room", "tunnel", "outdoor"]
        for t in map_types:
            patterns = [
                str(data_path / "maps_eval" / t / "*.png"),
                str(data_path / "maps_train" / t / "*.png"),
                str(data_path / "**" / t / "*.png")
            ]
            type_maps = []
            for pat in patterns:
                type_maps.extend(glob.glob(pat, recursive=True))
            type_maps = sorted(set(type_maps))[:3]
            maps.extend([Path(p) for p in type_maps])
    if not maps:
        print("No maps found. Falling back to glob all png.")
        map_files = glob.glob(str(data_path / "**/*.png"), recursive=True)
        maps = [Path(p) for p in sorted(map_files)[:9]]
    print(f"Evaluating on {len(maps)} maps.")
    results = []
    per_type = defaultdict(lambda: {"success": [], "dist": [], "explored": []})
    for map_path in maps:
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            done = False
            step_count = 0
            while not done and step_count < 128:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                done = info.get("done", False)
                step_count += 1
            metrics = env.get_metrics()
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            success = 1 if explored_rate > 0.9999 else 0
            env_type = get_env_type(map_path)
            ep_result = {
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            }
            results.append(ep_result)
            per_type[env_type]["success"].append(success)
            per_type[env_type]["dist"].append(travel_distance if success else 0.0)
            per_type[env_type]["explored"].append(explored_rate)
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            env_type = get_env_type(map_path)
            results.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
            per_type[env_type]["success"].append(0)
            per_type[env_type]["dist"].append(0.0)
            per_type[env_type]["explored"].append(0.0)
    total_episodes = len(results)
    success_rate = sum(r["success"] for r in results) / total_episodes if total_episodes > 0 else 0.0
    successful_dists = [r["travel_distance"] for r in results if r["success"] == 1]
    avg_dist = np.mean(successful_dists) if successful_dists else 0.0
    avg_explored = np.mean([r["explored_rate"] for r in results]) if results else 0.0
    per_type_dict = {}
    for t, data in per_type.items():
        n = len(data["success"])
        if n > 0:
            sr = np.mean(data["success"])
            succ_d = [data["dist"][i] for i in range(n) if data["success"][i] == 1]
            ed = np.mean(succ_d) if succ_d else 0.0
            er = np.mean(data["explored"])
            per_type_dict[t] = {
                "explored_rate": float(er),
                "travel_distance": float(ed),
                "success_rate": float(sr)
            }
    exploration_score = 0.0
    if successful_dists and avg_dist > 0:
        exploration_score = success_rate * (300.0 / avg_dist)
    output = {
        "explored_rate": float(avg_explored),
        "travel_distance": float(avg_dist),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_dict,
        "total_episodes": int(total_episodes)
    }
    return output

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    model = load_model(args.checkpoint)
    result = run_evaluation(args.data_path, model)
    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with open(out_path, "w") as f:
        json.dump(result, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {result['success_rate']:.4f}, Explored: {result['explored_rate']:.4f}, Avg dist: {result['travel_distance']:.2f}")
    proxy_score = result.get('success_rate', 0.0) * (300.0 / result['travel_distance']) if result.get('travel_distance', 0) > 0 else 0.0
    print(f"Proxy exploration_score: {proxy_score:.4f}")
    print("Local test on train subset done.")

if __name__ == "__main__":
    main()
